// data.gov.sg NEA Dengue Clusters (GeoJSON) -> case_clusters rows.
// Each cluster: LOCALITY -> area, CASE_SIZE -> active_cases, polygon centroid
// -> lat/lng, OBJECTID -> stable source_id (upsert key). The biggest cluster
// is flagged as the dashboard banner.
let raw = $input.first().json;
let gj = raw;
if (typeof raw === 'string') gj = JSON.parse(raw);
else if (raw && typeof raw.data === 'string') gj = JSON.parse(raw.data);
else if (raw && typeof raw.body === 'string') gj = JSON.parse(raw.body);
else if (raw && raw.body) gj = raw.body;
function centroid(geom){
  if(!geom) return [null,null];
  let ring = geom.type==='Polygon' ? geom.coordinates[0]
           : geom.type==='MultiPolygon' ? geom.coordinates[0][0] : null;
  if(!ring || !ring.length) return [null,null];
  let sx=0, sy=0; for(const p of ring){ sx+=p[0]; sy+=p[1]; }
  return [sy/ring.length, sx/ring.length]; // lat, lng
}
function titleCase(s){ return s.replace(/\b\w/g, c => c.toUpperCase()); }
const rows = [];
for (const f of (gj.features || [])) {
  const p = f.properties || {};
  const loc = (p.LOCALITY || '').trim();
  let cases = parseInt(p.CASE_SIZE, 10); if (isNaN(cases)) cases = 0;
  const [lat, lng] = centroid(f.geometry);
  if (!loc || lat === null) continue;
  const name = titleCase(loc);
  const risk = cases >= 50 ? 'critical' : cases >= 10 ? 'high' : 'medium';
  rows.push({
    disease: 'dengue',
    title: 'Dengue cluster at ' + name,
    description: cases + ' active dengue case(s) reported by NEA at ' + name + '.',
    area_name: name,
    latitude: Math.round(lat * 1e6) / 1e6,
    longitude: Math.round(lng * 1e6) / 1e6,
    active_cases: cases,
    critical_cases: cases >= 10 ? cases : 0,
    risk_level: risk,
    is_banner: false,
    source_id: 'nea-dengue-' + p.OBJECTID
  });
}
if (rows.length) {
  let ti = 0;
  for (let i = 1; i < rows.length; i++) if (rows[i].active_cases > rows[ti].active_cases) ti = i;
  rows[ti].is_banner = true;
}
return [{ json: { rows } }];

// Record today's totals so the dashboard can show a real day-over-day delta.
// Yesterday's snapshot stays frozen; today's is refreshed on every run.
const rows = ($('Build case_clusters rows').item.json.rows) || [];
let a = 0, c = 0;
for (const r of rows) { a += r.active_cases || 0; c += r.critical_cases || 0; }
const d = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Singapore' });
return [{ json: { snapshot_date: d, active_cases: a, critical_cases: c } }];
